import { describe, expect, it } from 'vitest';

import {
  LiquidMemorySessionManager,
  liquidMemoryStationSessionId,
  liquidMemoryTelemetryHeaders,
} from '../liquid-memory-session';
import type {
  Pipeline,
  PipelinePreparedPrefill,
  PrefillResult,
} from '../pipeline';

function prefill(): PrefillResult {
  return {
    logits: new Float32Array([0, 1, 0]),
    stationCallCount: 3,
    poisoned: false,
    poisonChunk: -1,
    tailResidual: new Float32Array([0.25, 0.5]),
  };
}

class FakePipeline {
  prepareCalls = 0;
  loadCalls = 0;
  saveCalls = 0;
  generateFromPrefillCalls = 0;
  saveKvSessionResult = true;
  private readonly sessions = new Map<string, number>();

  private assertStationSessionId(sessionId: string): void {
    expect(sessionId).toMatch(/^[A-Za-z0-9_-]{1,128}$/);
  }

  async preparePrefill(args: { promptTokens: Uint32Array }): Promise<PipelinePreparedPrefill> {
    this.prepareCalls += 1;
    return {
      prefill: prefill(),
      telemetry: {
        source: 'amplituhedron-miss',
        prefixHash: `test-${args.promptTokens.length}`,
        prefixLen: args.promptTokens.length,
        replayMs: 4,
        prefillMs: 9,
        captureScheduled: true,
        stationCallCount: 3,
      },
    };
  }

  async saveKvSession(sessionId: string, prefixLength: number): Promise<boolean> {
    this.assertStationSessionId(sessionId);
    this.saveCalls += 1;
    this.sessions.set(sessionId, prefixLength);
    return this.saveKvSessionResult;
  }

  async loadKvSession(sessionId: string): Promise<{ prefixLength: number } | null> {
    this.assertStationSessionId(sessionId);
    this.loadCalls += 1;
    const prefixLength = this.sessions.get(sessionId);
    return prefixLength === undefined ? null : { prefixLength };
  }

  async generateFromPrefill(args: {
    promptTokens: Uint32Array;
  }): Promise<Uint32Array> {
    this.generateFromPrefillCalls += 1;
    return new Uint32Array([...args.promptTokens, 42]);
  }

  async generate(args: { promptTokens: Uint32Array }): Promise<Uint32Array> {
    return new Uint32Array([...args.promptTokens, 42]);
  }
}

function tokens(length: number, seed: number): Uint32Array {
  return Uint32Array.from(
    Array.from({ length }, (_, index) => seed + index),
  );
}

describe('LiquidMemorySessionManager', () => {
  it('generates station-safe session ids for fat-station KV reuse', () => {
    const sessionId = liquidMemoryStationSessionId(
      'Qwen/Edit:7B experimental',
      'hash:with/slashes+symbols',
      4096,
    );

    expect(sessionId).toMatch(/^[A-Za-z0-9_-]{1,128}$/);
    expect(sessionId).toContain('qwen_edit_7b_experimental');
    expect(sessionId).toContain('4096');
  });

  it('stores only a session handle and reuses station KV on the warm path', async () => {
    const pipeline = new FakePipeline();
    const manager = new LiquidMemorySessionManager({
      pipeline: pipeline as unknown as Pipeline,
      hotCapacity: 2,
      warmCapacity: 2,
    });
    const promptTokens = tokens(8, 10);

    const cold = await manager.generate({
      model: 'qwen-edit',
      promptTokens,
      maxNewTokens: 1,
    });
    expect(cold.telemetry.status).toBe('miss');
    expect(cold.telemetry.kvSaved).toBe(true);
    expect(pipeline.prepareCalls).toBe(1);
    expect(pipeline.saveCalls).toBe(1);

    const warm = await manager.generate({
      model: 'qwen-edit',
      promptTokens,
      maxNewTokens: 1,
    });
    expect(warm.telemetry.status).toBe('hit');
    expect(warm.telemetry.restoreMs).toBeGreaterThanOrEqual(0);
    expect(pipeline.loadCalls).toBe(1);
    expect(pipeline.prepareCalls).toBe(1);
    expect(pipeline.generateFromPrefillCalls).toBe(2);
  });

  it('reuses retained local prefill for one-token warm hits when station KV capture fails', async () => {
    const pipeline = new FakePipeline();
    pipeline.saveKvSessionResult = false;
    const manager = new LiquidMemorySessionManager({
      pipeline: pipeline as unknown as Pipeline,
      hotCapacity: 2,
      warmCapacity: 2,
    });
    const promptTokens = tokens(8, 50);

    const cold = await manager.generate({
      model: 'qwen-edit',
      promptTokens,
      maxNewTokens: 1,
    });
    expect(cold.telemetry.status).toBe('capture_failed');
    expect(cold.telemetry.kvSaved).toBe(false);
    expect(cold.telemetry.items.hot).toBe(1);

    const warm = await manager.generate({
      model: 'qwen-edit',
      promptTokens,
      maxNewTokens: 1,
    });
    expect(warm.telemetry.status).toBe('hit');
    expect(warm.telemetry.kvSaved).toBe(false);
    expect(pipeline.loadCalls).toBe(0);
    expect(pipeline.prepareCalls).toBe(1);
    expect(pipeline.generateFromPrefillCalls).toBe(2);
  });

  it('does not reuse a local-only prefill for multi-token warm generation', async () => {
    const pipeline = new FakePipeline();
    pipeline.saveKvSessionResult = false;
    const manager = new LiquidMemorySessionManager({
      pipeline: pipeline as unknown as Pipeline,
      hotCapacity: 2,
      warmCapacity: 2,
    });
    const promptTokens = tokens(8, 75);

    await manager.generate({
      model: 'qwen-edit',
      promptTokens,
      maxNewTokens: 1,
    });
    const warm = await manager.generate({
      model: 'qwen-edit',
      promptTokens,
      maxNewTokens: 2,
    });
    expect(warm.telemetry.status).toBe('capture_failed');
    expect(pipeline.prepareCalls).toBe(2);
  });

  it('routes and vents session records under pressure', async () => {
    const pipeline = new FakePipeline();
    const manager = new LiquidMemorySessionManager({
      pipeline: pipeline as unknown as Pipeline,
      hotCapacity: 1,
      warmCapacity: 1,
    });

    await manager.generate({
      model: 'qwen-edit',
      promptTokens: tokens(128, 1000),
      maxNewTokens: 1,
    });
    const second = await manager.generate({
      model: 'qwen-edit',
      promptTokens: tokens(128, 2000),
      maxNewTokens: 1,
    });
    expect(second.telemetry.routeCount).toBeGreaterThanOrEqual(1);

    const third = await manager.generate({
      model: 'qwen-edit',
      promptTokens: tokens(128, 3000),
      maxNewTokens: 1,
    });
    expect(third.telemetry.ventCount).toBeGreaterThanOrEqual(1);
    expect(third.telemetry.items.hot).toBeLessThanOrEqual(1);
    expect(third.telemetry.items.warm).toBeLessThanOrEqual(1);
  });

  it('emits compact Thoth liquid-memory headers', () => {
    const sessionId = liquidMemoryStationSessionId('qwen-edit', '123', 5);
    const headers = liquidMemoryTelemetryHeaders({
      status: 'hit',
      prefixHash: '123',
      prefixLength: 5,
      sessionId,
      restoreMs: 7,
      kvSaved: true,
      pressure: { hot: 50, warm: 25 },
      items: { hot: 1, warm: 1 },
      ventCount: 2,
      routeCount: 3,
      prefill: {
        source: 'amplituhedron-hit',
        prefixHash: '123',
        prefixLen: 5,
        replayMs: 4,
        prefillMs: 0,
        captureScheduled: false,
        stationCallCount: 2,
      },
    });
    expect(headers['X-Thoth-Liquid-Memory']).toBe('hit');
    expect(headers['X-Thoth-Liquid-Prefix-Hash']).toBe('123');
    expect(headers['X-Thoth-Liquid-KV-Saved']).toBe('true');
    expect(headers['X-Thoth-Liquid-Prefill-Source']).toBe('amplituhedron-hit');
  });

  it('opens a circuit breaker after repeated kv-save failures and falls back to native', async () => {
    const pipeline = new FakePipeline();
    pipeline.saveKvSessionResult = false; // station accepts the route but never saves
    const manager = new LiquidMemorySessionManager({
      pipeline: pipeline as unknown as Pipeline,
      hotCapacity: 8,
      warmCapacity: 8,
    });

    // Three DISTINCT prompts → three consecutive cold capture_failed saves
    // (circuitThreshold = 3). Each still runs the liquid prefill+save attempt.
    for (let i = 0; i < 3; i += 1) {
      const r = await manager.generate({
        model: 'qwen-edit',
        promptTokens: tokens(8, 100 + i * 10),
        maxNewTokens: 1,
      });
      expect(r.telemetry.status).toBe('capture_failed');
    }
    expect(pipeline.saveCalls).toBe(3);
    expect(pipeline.prepareCalls).toBe(3);

    // Breaker is now OPEN: the next request takes the native fast path —
    // no new prefill, no new save attempt — reported as 'disabled'.
    const afterTrip = await manager.generate({
      model: 'qwen-edit',
      promptTokens: tokens(8, 999),
      maxNewTokens: 1,
    });
    expect(afterTrip.telemetry.status).toBe('disabled');
    expect(pipeline.saveCalls).toBe(3); // no further save attempts
    expect(pipeline.prepareCalls).toBe(3); // no further prefill orchestration
  });
});
